import torch
import torch.nn as nn

class PostNormResidual(nn.Module):
    """Post-norm: LayerNorm(x + sublayer(x)) — original Transformer / BERT."""
    def __init__(self, d_model: int, sublayer: nn.Module, dropout: float = 0.1):
        super().__init__()
        self.sublayer = sublayer
        self.norm = nn.LayerNorm(d_model)
        self.drop = nn.Dropout(dropout)

    def forward(self, x: torch.Tensor, **kwargs) -> torch.Tensor:
        return self.norm(x + self.drop(self.sublayer(x, **kwargs)))


class PreNormResidual(nn.Module):
    """Pre-norm: x + sublayer(LayerNorm(x)) — GPT-2+, LLaMA."""
    def __init__(self, d_model: int, sublayer: nn.Module, dropout: float = 0.1):
        super().__init__()
        self.sublayer = sublayer
        self.norm = nn.LayerNorm(d_model)
        self.drop = nn.Dropout(dropout)

    def forward(self, x: torch.Tensor, **kwargs) -> torch.Tensor:
        return x + self.drop(self.sublayer(self.norm(x), **kwargs))


# Typical usage inside a transformer block
class TransformerBlock(nn.Module):
    def __init__(self, d_model: int, num_heads: int, d_ff: int):
        super().__init__()
        from torch.nn import MultiheadAttention
        self_attn = MultiheadAttention(d_model, num_heads, batch_first=True)
        ffn = nn.Sequential(
            nn.Linear(d_model, d_ff), nn.GELU(), nn.Linear(d_ff, d_model)
        )
        self.attn_residual = PreNormResidual(d_model, self_attn)
        self.ffn_residual  = PreNormResidual(d_model, ffn)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Attention sublayer (MHA returns (output, weights))
        x = x + self.attn_residual.drop(
            self.attn_residual.sublayer(
                self.attn_residual.norm(x),
                self.attn_residual.norm(x),
                self.attn_residual.norm(x),
            )[0]
        )
        # FFN sublayer
        x = self.ffn_residual(x)
        return x

import torch
import torch.nn as nn
from torch.utils.checkpoint import checkpoint

class ResidualBlock(nn.Module):
    def __init__(self, d):
        super().__init__()
        self.fc = nn.Sequential(nn.LayerNorm(d), nn.Linear(d, d*4), nn.GELU(), nn.Linear(d*4, d))
    def forward(self, x):
        return x + self.fc(x)

# Without checkpointing: stores all activations → high memory
def forward_standard(blocks, x):
    for block in blocks:
        x = block(x)
    return x

# With gradient checkpointing: recomputes activations during backward → low memory
def forward_checkpointed(blocks, x):
    for block in blocks:
        x = checkpoint(block, x, use_reentrant=False)
    return x

blocks = nn.ModuleList([ResidualBlock(512) for _ in range(24)])
x = torch.randn(8, 128, 512, requires_grad=True)

# Compare peak memory (conceptual; measure with torch.cuda.max_memory_allocated)
out_std = forward_standard(blocks, x)
print(f"Standard output shape: {out_std.shape}")

out_ckpt = forward_checkpointed(blocks, x.detach().requires_grad_(True))
print(f"Checkpointed output shape: {out_ckpt.shape}")
